// components/layout/Sidebar.tsx - Updated version
'use client'

import Link from 'next/link'
import { usePathname } from 'next/navigation'
import { 
  FiHome, 
  FiUsers, 
  FiMap, 
  FiNavigation, 
  FiBell, 
  FiBarChart2,
  FiAlertCircle,
  FiLogOut,
  FiChevronLeft,
  FiChevronRight
} from 'react-icons/fi'
import { useState } from 'react'
import { supabase } from '../../../lib/supabase'

const menuItems = [
  { name: 'Dashboard', href: '/dashboard', icon: FiHome },
  { name: 'Users', href: '/dashboard/users', icon: FiUsers },
  { name: 'Routes', href: '/dashboard/routes', icon: FiMap },
  { name: 'Stops', href: '/dashboard/stops', icon: FiNavigation },
  { name: 'Notifications', href: '/dashboard/notifications', icon: FiBell },
  { name: 'Analytics', href: '/dashboard/analytics', icon: FiBarChart2 },
  { name: 'Alerts', href: '/dashboard/alerts', icon: FiAlertCircle },
]

export function Sidebar() {
  const pathname = usePathname()
  const [collapsed, setCollapsed] = useState(false)

  const handleLogout = async () => {
    await supabase.auth.signOut()
    window.location.href = '/login'
  }

  return (
    <div className={`${collapsed ? 'w-20' : 'w-64'} bg-primary text-white h-screen flex flex-col transition-all duration-300 fixed left-0 top-0 z-50`}>
      <div className="p-6 border-b border-primary-light">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-white text-primary p-2 rounded-lg">
              <FiMap size={24} />
            </div>
            {!collapsed && (
              <>
                <div>
                  <h1 className="text-xl font-bold">Ghana Trotro</h1>
                  <p className="text-primary-light text-sm">Admin Dashboard</p>
                </div>
              </>
            )}
          </div>
          
          {/* Collapse button - moved to top right */}
          {!collapsed && (
            <button
              onClick={() => setCollapsed(!collapsed)}
              className="p-2 rounded-lg hover:bg-primary-light/30 transition-colors"
              title="Collapse sidebar"
            >
              <FiChevronLeft size={20} />
            </button>
          )}
        </div>
      </div>

      <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
        {menuItems.map((item) => {
          const Icon = item.icon
          const isActive = pathname === item.href || pathname?.startsWith(item.href + '/')
          
          return (
            <Link
              key={item.name}
              href={item.href}
              className={`flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${
                isActive 
                  ? 'bg-primary-light text-white' 
                  : 'hover:bg-primary-light/50 text-primary-light'
              }`}
              title={collapsed ? item.name : ''}
            >
              <Icon size={20} />
              {!collapsed && <span>{item.name}</span>}
            </Link>
          )
        })}
      </nav>

      <div className="p-4 border-t border-primary-light">
        {collapsed ? (
          <div className="space-y-4">
            {/* Expand button when collapsed */}
            <button
              onClick={() => setCollapsed(!collapsed)}
              className="flex items-center justify-center p-3 rounded-lg hover:bg-primary-light/30 transition-colors w-full"
              title="Expand sidebar"
            >
              <FiChevronRight size={20} />
            </button>
            
            <button
              onClick={handleLogout}
              className="flex items-center justify-center p-3 rounded-lg hover:bg-error/20 text-error transition-colors w-full"
              title="Logout"
            >
              <FiLogOut size={20} />
            </button>
          </div>
        ) : (
          <div className="space-y-2">
            <button
              onClick={handleLogout}
              className="flex items-center space-x-3 px-4 py-3 rounded-lg hover:bg-error/20 text-error transition-colors w-full"
            >
              <FiLogOut size={20} />
              <span>Logout</span>
            </button>
          </div>
        )}
      </div>
    </div>
  )
}